package store

import (
	"encoding/json"
	"fmt"
	"os"
)

type Record struct {
	ID    string `json:"id"`
	Value int    `json:"value"`
}

func LoadShards(paths []string) ([]Record, error) {
	var records []Record
	for _, p := range paths {
		f, err := os.Open(p)
		if err != nil {
			return nil, fmt.Errorf("open shard %s: %w", p, err)
		}
		var batch []Record
		if err := json.NewDecoder(f).Decode(&batch); err != nil {
			f.Close()
			return nil, fmt.Errorf("decode shard %s: %w", p, err)
		}
		f.Close()
		records = append(records, batch...)
	}
	return records, nil
}

